import { resolveFfprobePath } from "./processor/ffmpegPath.js";
import type { FFprobeResult } from "../Types/index.js";

interface ProbeOptions {
  ffprobePath?: string;
}

function isServer(): boolean {
  return typeof globalThis !== "undefined" && "process" in globalThis && !("window" in globalThis);
}

async function spawnAndCollect(
  cmd: string,
  args: string[],
): Promise<{ stdout: string; stderr: string; code: number | null }> {
  if ("Bun" in globalThis) {
    const proc = Bun.spawnSync([cmd, ...args]);
    return {
      stdout: proc.stdout.toString(),
      stderr: proc.stderr.toString(),
      code: proc.exitCode,
    };
  }

  const { spawn } = await import("node:child_process");
  return new Promise((resolve, reject) => {
    const chunks: Buffer[] = [];
    const errChunks: Buffer[] = [];
    const cp = spawn(cmd, args, { stdio: ["ignore", "pipe", "pipe"] });
    cp.stdout!.on("data", (chunk: Buffer) => chunks.push(chunk));
    cp.stderr!.on("data", (chunk: Buffer) => errChunks.push(chunk));
    cp.on("error", (err) => reject(err));
    cp.on("close", (code) => {
      resolve({
        stdout: Buffer.concat(chunks).toString("utf-8"),
        stderr: Buffer.concat(errChunks).toString("utf-8"),
        code,
      });
    });
  });
}

export async function probe(input: string, options?: ProbeOptions): Promise<FFprobeResult> {
  if (!input || typeof input !== "string") {
    throw new Error("probe(): input must be a non-empty file path or URL");
  }

  if (!isServer()) {
    throw new Error("probe(): ffprobe is only available in server-side runtimes (Node/Bun/Deno)");
  }

  const ffprobePath = await resolveFfprobePath(options?.ffprobePath);
  const result = await spawnAndCollect(ffprobePath, [
    "-v",
    "quiet",
    "-print_format",
    "json",
    "-show_format",
    "-show_streams",
    input,
  ]);

  if (result.code !== 0) {
    const msg = result.stderr.trim() || `ffprobe exited with code ${result.code}`;
    throw new Error(`probe() failed: ${msg}`);
  }

  try {
    const parsed = JSON.parse(result.stdout) as FFprobeResult;
    if (!parsed.streams) parsed.streams = [];
    if (!parsed.format) parsed.format = {};
    return parsed;
  } catch (err) {
    throw new Error(`probe() failed to parse ffprobe output: ${(err as Error).message}`);
  }
}

export async function isFfprobeAvailable(): Promise<boolean> {
  if (!isServer()) return false;
  try {
    await resolveFfprobePath();
    return true;
  } catch {
    return false;
  }
}
